    public void WFiltro_Class_WithDifferentLengths_ShouldAddParameter(string value, int expectedLength)
    {
        // Arrange
        var filtro = new FilterOponentes
        {
            Class = value,
            WildcardChar = '%',
            LogicalOperator = TSql.And
        };
        // Act
        var result = _serviceS.WFiltroOponentes(filtro);
        // Assert
        result.Should().NotBeNull();
        result.Value.parametros.Should().HaveCount(1);
        var param = result.Value.parametros.First();
        // Value should be %value% so length is value.Length + 2
        param?.Value?.ToString()?.Length.Should().Be(expectedLength + 1);
    }

